import java.util.concurrent.*;
import java.util.*;

public class EventBus {
    // ConcurrentHashMap ensures thread-safe subscriber storage
    private final Map<Class<?>, List<Consumer<?>>> subscribers
        = new ConcurrentHashMap<>();

    // Thread pool for async event processing
    private final ExecutorService executor
        = Executors.newFixedThreadPool(4);

    // Register a subscriber for a specific event type
    public <T> void subscribe(Class<T> eventType, Consumer<T> handler) {
        subscribers.computeIfAbsent(eventType, k -> new CopyOnWriteArrayList<>());
        subscribers.get(eventType).add(handler);
    }

    // Publish event to all subscribers (async)
    public <T> void publish(T event) {
        List<Consumer<?>> handlers = subscribers.get(event.getClass());
        if (handlers != null) {
            for (Consumer<?> handler : handlers) {
                executor.submit(() -> ((Consumer<T>) handler).accept(event));
            }
        }
    }
}
// Expected: events are processed by all subscribers in parallel
